def __init__(
    self,
    enable_disk_cache: bool,
    enable_memory_cache: bool,
    disk_cache_dir: str,
    disk_size_limit_bytes: Optional[int] = 1024 * 1024 * 10,
    memory_max_entries: Optional[int] = 1000000,
    compress: Optional[str] = None,
    cull_limit: Optional[int] = None,
    eviction_policy: Optional[str] = None,
):
    """
    Args:
        enable_disk_cache: Whether to enable on-disk cache.
        enable_memory_cache: Whether to enable in-memory cache.
        disk_cache_dir: The directory where the disk cache is stored.
        disk_size_limit_bytes: The maximum size of the disk cache (in bytes).
        memory_max_entries: The maximum size of the in-memory cache (in number of items).
        compress: The compression codec to use for values written to the on-disk cache.
            One of `"gzip"`, `"zlib"`, or `None` (no compression, the default). Only
            affects the disk layer; the in-memory cache always stores live Python objects.
        cull_limit: The number of entries culled from the disk cache each time it exceeds
            its size limit. Passed through to `diskcache.FanoutCache`.
        eviction_policy: The eviction policy used by the disk cache (e.g.
            `"least-recently-stored"`, `"least-recently-used"`, `"least-frequently-used"`,
            `"none"`). Passed through to `diskcache.FanoutCache`.
    """
    if compress not in _CODEC_BY_NAME:
        raise ValueError(f"`compress` must be one of {list(_CODEC_BY_NAME)}, got {compress!r}.")

    self.enable_disk_cache = enable_disk_cache
    self.enable_memory_cache = enable_memory_cache
    self.compress = compress
    if self.enable_memory_cache:
        self.memory_cache = LRUCache(maxsize=memory_max_entries)
    else:
        self.memory_cache = {}
    if self.enable_disk_cache:
        disk_cache_settings = {}
        if cull_limit is not None:
            disk_cache_settings["cull_limit"] = cull_limit
        if eviction_policy is not None:
            disk_cache_settings["eviction_policy"] = eviction_policy
        self.disk_cache = FanoutCache(
            shards=16,
            timeout=10,
            directory=disk_cache_dir,
            size_limit=disk_size_limit_bytes,
            **disk_cache_settings,
        )
    else:
        self.disk_cache = {}

    self._lock = threading.RLock()

def set_compression(self, compress: Optional[str]) -> None:
    """Change the compression codec used for future writes to the on-disk cache.

    Existing entries are unaffected until they are next written; reads continue to support
    both compressed and legacy uncompressed entries regardless of this setting.
    """
    if compress not in _CODEC_BY_NAME:
        raise ValueError(f"`compress` must be one of {list(_CODEC_BY_NAME)}, got {compress!r}.")
    self.compress = compress

def _serialize_for_disk(self, value: Any) -> bytes:
    payload = pickle.dumps(value)
    codec = _CODEC_BY_NAME[self.compress]
    if codec == _CODEC_GZIP:
        payload = gzip.compress(payload)
    elif codec == _CODEC_ZLIB:
        payload = zlib.compress(payload)
    return _CACHE_BLOB_MAGIC + bytes([codec]) + payload

def _deserialize_from_disk(self, blob: Any) -> Any:
    if not isinstance(blob, (bytes, bytearray)) or blob[:4] != _CACHE_BLOB_MAGIC:
        # Legacy entry written before compression support was added: a raw pickle blob
        # (or already-deserialized object) with no magic header.
        return blob if not isinstance(blob, (bytes, bytearray)) else pickle.loads(blob)

    codec = blob[4]
    payload = bytes(blob[5:])
    if codec == _CODEC_GZIP:
        payload = gzip.decompress(payload)
    elif codec == _CODEC_ZLIB:
        payload = zlib.decompress(payload)
    elif codec != _CODEC_NONE:
        raise ValueError(f"Unknown cache blob codec byte: {codec!r}")
    return pickle.loads(payload)

